import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  // Forma funcional: use quando o novo valor depende do anterior
  const increment = () => setCount((prev) => prev + 1);

  return (
    <div>
      <p>Contagem: {count}</p>
      <button onClick={increment}>+1</button>
    </div>
  );
}

import { useState, useEffect } from 'react';

function UserProfile({ userId }: { userId: number }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function load() {
      const data = await fetchUser(userId);
      if (!cancelled) setUser(data);
    }

    void load();

    // cleanup: evita atualizar estado em componente desmontado
    return () => { cancelled = true; };
  }, [userId]); // roda novamente quando userId mudar

  return <div>{user?.name ?? 'Carregando...'}</div>;
}

import { useCallback, useMemo } from 'react';

function List({ items, onSelect }: Props) {
  // useCallback: mesma referência de função entre renders
  const handleClick = useCallback(
    (id: number) => onSelect(id),
    [onSelect]
  );

  // useMemo: recalcula só quando items mudar
  const sorted = useMemo(
    () => [...items].sort((a, b) => a.name.localeCompare(b.name)),
    [items]
  );

  return sorted.map((item) => (
    <div key={item.id} onClick={() => handleClick(item.id)}>
      {item.name}
    </div>
  ));
}

import { useRef, useEffect } from 'react';

function AutoFocusInput() {
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  return <input ref={inputRef} placeholder="foca automaticamente" />;
}

// Também para guardar valores mutáveis
function Timer() {
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  function start() {
    intervalRef.current = setInterval(() => console.log('tick'), 1000);
  }

  function stop() {
    if (intervalRef.current) clearInterval(intervalRef.current);
  }
}

